import { useContext } from 'react';


import { Icon } from './Icon.js';
import { unitStyle, valueArea, valueStyle } from './Value.sty.js';
import { Flex } from '../../../../../layouts/flex/Flex.js';
import { replaceSlashedZero } from '../../../typographyStyles.sty.js';
import { isReactNode } from '../../../utils/is-react-node.js';
import { FontSizeContext } from '../contexts/font-size.context.js';
import { SingleValueContext } from '../contexts/single-value.context.js';

export const Value = () => {
  const { prefixIcon, value, unit, alignment } = useContext(SingleValueContext);

  const { refCallback } = useContext(FontSizeContext);

  return (
    <Flex className={valueArea} ref={refCallback} justifyContent={alignment}>
      <Icon />
      <span
        className={valueStyle({ isReactNode: isReactNode(prefixIcon) })}
        data-testid="single-value-chart-value"
        ref={refCallback}
      >
        <span className={replaceSlashedZero}>{value}</span>
        {unit.length > 0 ? <small className={unitStyle}>{unit}</small> : null}
      </span>
    </Flex>
  );
};

Value['displayName'] = 'SingleValue.Value';
